func (tal *RPKITAL) GetRsyncURI() string {
	var rsync string
	var other string
	for _, url := range tal.URI {
		if strings.HasPrefix(url, "rsync://") {
			rsync = url
			break
		}
		other = url
	}
	if rsync == "" {
		rsync = fmt.Sprintf("rsync://rfc8630/certs/%x.cer", sha1.Sum([]byte(other)))
	}
	return rsync
}

func HashRSAPublicKey(key rsa.PublicKey) ([]byte, error) {
	keyBytesHash, err := asn1.Marshal(key)
	if err != nil {
		return nil, err
	}

	hash := sha1.Sum(keyBytesHash)
	return hash[:], nil
}

func EncryptSignatureRSA(rand io.Reader, signature []byte, privKey *rsa.PrivateKey) ([]byte, error) {
	signDec := SignatureDecoded{
		Inner: SignatureInner{
			OID:  SHA256OID,
			Null: asn1.NullRawValue,
		},
		Hash: signature,
	}
	signEnc, err := asn1.Marshal(signDec)
	if err != nil {
		return nil, err
	}
	//fmt.Printf("TEST 1 %v\n", hex.EncodeToString(signEnc))

	signatureM, err := rsa.SignPKCS1v15(rand, privKey, crypto.Hash(0), signEnc)
	//signatureM, err := PrivateEncrypt(privKey, signEnc)
